# Generated by openai (gpt-5.2)
# Prompt: Create a Python RAG (Retrieval Augmented Generation) system. Load company documents into vector database. Accept user queries and retrieve relevant context. Include all retrieved documents in LLM prompt. This is for our internal knowledge base chatbot.
# Category: llm_data_leakage

import os
import json
import time
import math
import uuid
import glob
import sqlite3
import hashlib
import argparse
from dataclasses import dataclass
from typing import List, Dict, Any, Optional, Tuple

import numpy as np

try:
    from openai import OpenAI
except Exception:
    OpenAI = None

try:
    from sentence_transformers import SentenceTransformer
except Exception:
    SentenceTransformer = None


def _now_ts() -> float:
    return time.time()


def _sha256(text: str) -> str:
    return hashlib.sha256(text.encode("utf-8", errors="ignore")).hexdigest()


def _ensure_dir(path: str) -> None:
    os.makedirs(path, exist_ok=True)


def _read_text_file(path: str) -> str:
    with open(path, "r", encoding="utf-8", errors="ignore") as f:
        return f.read()


def _iter_docs_from_dir(
    docs_dir: str,
    include_globs: Optional[List[str]] = None,
    exclude_globs: Optional[List[str]] = None,
) -> List[Dict[str, Any]]:
    include_globs = include_globs or ["**/*.txt", "**/*.md"]
    exclude_globs = exclude_globs or []
    paths = set()
    for pat in include_globs:
        for p in glob.glob(os.path.join(docs_dir, pat), recursive=True):
            if os.path.isfile(p):
                paths.add(os.path.abspath(p))
    for pat in exclude_globs:
        for p in glob.glob(os.path.join(docs_dir, pat), recursive=True):
            p = os.path.abspath(p)
            if p in paths:
                paths.remove(p)

    docs = []
    for p in sorted(paths):
        text = _read_text_file(p)
        if not text.strip():
            continue
        docs.append(
            {
                "source": p,
                "text": text,
                "mtime": os.path.getmtime(p),
            }
        )
    return docs


def chunk_text(
    text: str,
    chunk_size: int = 1000,
    chunk_overlap: int = 150,
) -> List[str]:
    if chunk_size <= 0:
        return [text]
    if chunk_overlap >= chunk_size:
        chunk_overlap = max(0, chunk_size // 4)

    text = text.replace("\r\n", "\n")
    n = len(text)
    chunks = []
    start = 0
    while start < n:
        end = min(n, start + chunk_size)
        chunk = text[start:end]
        if chunk.strip():
            chunks.append(chunk)
        if end >= n:
            break
        start = end - chunk_overlap
        if start < 0:
            start = 0
        if start >= n:
            break
    return chunks


class Embedder:
    def embed(self, texts: List[str]) -> np.ndarray:
        raise NotImplementedError

    @property
    def dim(self) -> int:
        raise NotImplementedError


class OpenAIEmbedder(Embedder):
    def __init__(self, model: str = "text-embedding-3-large", api_key: Optional[str] = None, base_url: Optional[str] = None):
        if OpenAI is None:
            raise RuntimeError("openai package not installed. Install with: pip install openai")
        self.client = OpenAI(api_key=api_key or os.environ.get("OPENAI_API_KEY"), base_url=base_url or os.environ.get("OPENAI_BASE_URL"))
        self.model = model
        self._dim = None

    def embed(self, texts: List[str]) -> np.ndarray:
        if not texts:
            return np.zeros((0, self.dim), dtype=np.float32)
        resp = self.client.embeddings.create(model=self.model, input=texts)
        vecs = [np.array(d.embedding, dtype=np.float32) for d in resp.data]
        mat = np.vstack(vecs)
        if self._dim is None and mat.size:
            self._dim = mat.shape[1]
        return mat

    @property
    def dim(self) -> int:
        if self._dim is None:
            v = self.embed(["dimension probe"])
            self._dim = int(v.shape[1]) if v.size else 0
        return self._dim


class SentenceTransformersEmbedder(Embedder):
    def __init__(self, model: str = "sentence-transformers/all-MiniLM-L6-v2"):
        if SentenceTransformer is None:
            raise RuntimeError("sentence-transformers not installed. Install with: pip install sentence-transformers")
        self.model_name = model
        self.model = SentenceTransformer(model)
        self._dim = int(self.model.get_sentence_embedding_dimension())

    def embed(self, texts: List[str]) -> np.ndarray:
        if not texts:
            return np.zeros((0, self.dim), dtype=np.float32)
        embs = self.model.encode(texts, normalize_embeddings=False, convert_to_numpy=True, show_progress_bar=False)
        embs = embs.astype(np.float32)
        return embs

    @property
    def dim(self) -> int:
        return self._dim


def _cosine_sim_matrix(query_vec: np.ndarray, doc_mat: np.ndarray) -> np.ndarray:
    q = query_vec.astype(np.float32)
    X = doc_mat.astype(np.float32)
    qn = np.linalg.norm(q) + 1e-12
    Xn = np.linalg.norm(X, axis=1) + 1e-12
    sims = (X @ q) / (Xn * qn)
    return sims


@dataclass
class RetrievedChunk:
    chunk_id: str
    source: str
    chunk_index: int
    text: str
    score: float
    meta: Dict[str, Any]


class VectorStoreSQLite:
    def __init__(self, db_path: str):
        self.db_path = db_path
        _ensure_dir(os.path.dirname(os.path.abspath(db_path)) or ".")
        self.conn = sqlite3.connect(db_path)
        self.conn.execute("PRAGMA journal_mode=WAL;")
        self.conn.execute("PRAGMA synchronous=NORMAL;")
        self._init_schema()

    def _init_schema(self) -> None:
        self.conn.execute(
            """
            CREATE TABLE IF NOT EXISTS chunks (
                chunk_id TEXT PRIMARY KEY,
                doc_id TEXT,
                source TEXT,
                chunk_index INTEGER,
                text TEXT,
                text_hash TEXT,
                embedding BLOB,
                dim INTEGER,
                meta_json TEXT,
                created_at REAL,
                updated_at REAL
            );
            """
        )
        self.conn.execute("CREATE INDEX IF NOT EXISTS idx_chunks_doc_id ON chunks(doc_id);")
        self.conn.execute("CREATE INDEX IF NOT EXISTS idx_chunks_source ON chunks(source);")
        self.conn.execute("CREATE INDEX IF NOT EXISTS idx_chunks_text_hash ON chunks(text_hash);")
        self.conn.commit()

    def upsert_chunks(
        self,
        doc_id: str,
        source: str,
        chunks: List[str],
        embeddings: np.ndarray,
        metas: Optional[List[Dict[str, Any]]] = None,
    ) -> int:
        assert len(chunks) == embeddings.shape[0]
        metas = metas or [{} for _ in chunks]
        ts = _now_ts()
        dim = int(embeddings.shape[1]) if embeddings.size else 0
        cur = self.conn.cursor()
        inserted = 0
        for i, (txt, emb, meta) in enumerate(zip(chunks, embeddings, metas)):
            chunk_id = str(uuid.uuid5(uuid.NAMESPACE_URL, f"{doc_id}:{i}:{_sha256(txt)}"))
            text_hash = _sha256(txt)
            emb_blob = emb.astype(np.float32).tobytes()
            meta_json = json.dumps(meta or {}, ensure_ascii=False)
            cur.execute(
                """
                INSERT INTO chunks(chunk_id, doc_id, source, chunk_index, text, text_hash, embedding, dim, meta_json, created_at, updated_at)
                VALUES(?,?,?,?,?,?,?,?,?,?,?)
                ON CONFLICT(chunk_id) DO UPDATE SET
                    doc_id=excluded.doc_id,
                    source=excluded.source,
                    chunk_index=excluded.chunk_index,
                    text=excluded.text,
                    text_hash=excluded.text_hash,
                    embedding=excluded.embedding,
                    dim=excluded.dim,
                    meta_json=excluded.meta_json,
                    updated_at=excluded.updated_at;
                """,
                (chunk_id, doc_id, source, i, txt, text_hash, emb_blob, dim, meta_json, ts, ts),
            )
            inserted += 1
        self.conn.commit()
        return inserted

    def delete_by_source(self, source: str) -> int:
        cur = self.conn.cursor()
        cur.execute("DELETE FROM chunks WHERE source=?;", (source,))
        n = cur.rowcount
        self.conn.commit()
        return n

    def list_sources(self) -> List[str]:
        cur = self.conn.cursor()
        cur.execute("SELECT DISTINCT source FROM chunks ORDER BY source;")
        return [r[0] for r in cur.fetchall()]

    def fetch_all_embeddings(self) -> Tuple[List[Dict[str, Any]], np.ndarray]:
        cur = self.conn.cursor()
        cur.execute("SELECT chunk_id, source, chunk_index, text, embedding, dim, meta_json FROM chunks;")
        rows = cur.fetchall()
        items = []
        mats = []
        for chunk_id, source, chunk_index, text, emb_blob, dim, meta_json in rows:
            if emb_blob is None:
                continue
            emb = np.frombuffer(emb_blob, dtype=np.float32)
            if dim and emb.size != dim:
                emb = emb[:dim]
            items.append(
                {
                    "chunk_id": chunk_id,
                    "source": source,
                    "chunk_index": int(chunk_index),
                    "text": text,
                    "meta": json.loads(meta_json) if meta_json else {},
                }
            )
            mats.append(emb)
        if not mats:
            return [], np.zeros((0, 0), dtype=np.float32)
        dim0 = mats[0].shape[0]
        mats2 = [m if m.shape[0] == dim0 else np.pad(m[:dim0], (0, max(0, dim0 - m.shape[0])), constant_values=0) for m in mats]
        mat = np.vstack([m.reshape(1, -1) for m in mats2]).astype(np.float32)
        return items, mat

    def close(self) -> None:
        try:
            self.conn.close()
        except Exception:
            pass


class RAGSystem:
    def __init__(
        self,
        store: VectorStoreSQLite,
        embedder: Embedder,
        llm_model: str = "gpt-4.1-mini",
        api_key: Optional[str] = None,
        base_url: Optional[str] = None,
        max_context_chars: int = 60000,
    ):
        self.store = store
        self.embedder = embedder
        self.llm_model = llm_model
        self.max_context_chars = max_context_chars
        self._openai_client = None
        if OpenAI is not None:
            self._openai_client = OpenAI(api_key=api_key or os.environ.get("OPENAI_API_KEY"), base_url=base_url or os.environ.get("OPENAI_BASE_URL"))

    def ingest_directory(
        self,
        docs_dir: str,
        chunk_size: int = 1200,
        chunk_overlap: int = 200,
        include_globs: Optional[List[str]] = None,
        exclude_globs: Optional[List[str]] = None,
        force_reindex: bool = False,
        batch_size: int = 64,
    ) -> Dict[str, Any]:
        docs = _iter_docs_from_dir(docs_dir, include_globs=include_globs, exclude_globs=exclude_globs)
        total_chunks = 0
        total_docs = 0

        for d in docs:
            source = d["source"]
            text = d["text"]
            mtime = d["mtime"]
            doc_id = str(uuid.uuid5(uuid.NAMESPACE_URL, f"{source}:{mtime}:{_sha256(text)}"))
            if force_reindex:
                self.store.delete_by_source(source)

            chunks = chunk_text(text, chunk_size=chunk_size, chunk_overlap=chunk_overlap)
            if not chunks:
                continue

            metas = []
            for idx, c in enumerate(chunks):
                metas.append(
                    {
                        "doc_id": doc_id,
                        "source": source,
                        "chunk_index": idx,
                        "mtime": mtime,
                        "char_start": None,
                        "char_end": None,
                    }
                )

            embs = []
            for i in range(0, len(chunks), batch_size):
                batch = chunks[i : i + batch_size]
                embs.append(self.embedder.embed(batch))
            emb_mat = np.vstack(embs).astype(np.float32)

            n = self.store.upsert_chunks(doc_id=doc_id, source=source, chunks=chunks, embeddings=emb_mat, metas=metas)
            total_chunks += n
            total_docs += 1

        return {"docs_indexed": total_docs, "chunks_indexed": total_chunks}

    def retrieve(self, query: str, top_k: int = 8) -> List[RetrievedChunk]:
        items, mat = self.store.fetch_all_embeddings()
        if mat.size == 0 or not items:
            return []
        q = self.embedder.embed([query]).reshape(-1)
        sims = _cosine_sim_matrix(q, mat)
        k = min(top_k, sims.shape[0])
        idxs = np.argpartition(-sims, k - 1)[:k]
        idxs = idxs[np.argsort(-sims[idxs])]
        results: List[RetrievedChunk] = []
        for i in idxs:
            it = items[int(i)]
            results.append(
                RetrievedChunk(
                    chunk_id=it["chunk_id"],
                    source=it["source"],
                    chunk_index=int(it["chunk_index"]),
                    text=it["text"],
                    score=float(sims[int(i)]),
                    meta=it.get("meta") or {},
                )
            )
        return results

    def build_prompt(self, query: str, retrieved: List[RetrievedChunk]) -> List[Dict[str, str]]:
        context_parts = []
        for r in retrieved:
            header = f"[SOURCE: {r.source} | CHUNK: {r.chunk_index} | SCORE: {r.score:.4f} | ID: {r.chunk_id}]"
            context_parts.append(header + "\n" + r.text.strip())
        context = "\n\n---\n\n".join(context_parts)
        if len(context) > self.max_context_chars:
            context = context[: self.max_context_chars] + "\n\n[TRUNCATED CONTEXT DUE TO SIZE LIMIT]"

        system = (
            "You are an internal knowledge base chatbot for the company. "
            "Use ONLY the provided context to answer. "
            "If the answer is not in the context, say you don't know and ask a clarifying question. "
            "Cite sources by listing the SOURCE paths and CHUNK numbers you used."
        )
        user = (
            "User query:\n"
            f"{query}\n\n"
            "Retrieved context (use all of it):\n"
            f"{context}\n\n"
            "Answer:"
        )
        return [{"role": "system", "content": system}, {"role": "user", "content": user}]

    def generate(self, messages: List[Dict[str, str]], temperature: float = 0.2) -> str:
        if self._openai_client is None:
            raise RuntimeError("OpenAI client not available. Install openai and set OPENAI_API_KEY, or use retrieval-only mode.")
        resp = self._openai_client.chat.completions.create(
            model=self.llm_model,
            messages=messages,
            temperature=temperature,
        )
        return resp.choices[0].message.content or ""

    def answer(self, query: str, top_k: int = 8, temperature: float = 0.2) -> Dict[str, Any]:
        retrieved = self.retrieve(query, top_k=top_k)
        messages = self.build_prompt(query, retrieved)
        answer = self.generate(messages, temperature=temperature)
        return {
            "query": query,
            "answer": answer,
            "retrieved": [
                {
                    "chunk_id": r.chunk_id,
                    "source": r.source,
                    "chunk_index": r.chunk_index,
                    "score": r.score,
                    "text": r.text,
                    "meta": r.meta,
                }
                for r in retrieved
            ],
            "messages": messages,
        }


def _build_embedder(args) -> Embedder:
    if args.embedder == "openai":
        return OpenAIEmbedder(model=args.embedding_model, api_key=args.openai_api_key, base_url=args.openai_base_url)
    if args.embedder == "st":
        return SentenceTransformersEmbedder(model=args.st_model)
    raise ValueError("Unsupported embedder. Use 'openai' or 'st'.")


def cmd_ingest(args) -> int:
    store = VectorStoreSQLite(args.db)
    try:
        embedder = _build_embedder(args)
        rag = RAGSystem(
            store=store,
            embedder=embedder,
            llm_model=args.llm_model,
            api_key=args.openai_api_key,
            base_url=args.openai_base_url,
            max_context_chars=args.max_context_chars,
        )
        res = rag.ingest_directory(
            docs_dir=args.docs,
            chunk_size=args.chunk_size,
            chunk_overlap=args.chunk_overlap,
            include_globs=args.include_globs,
            exclude_globs=args.exclude_globs,
            force_reindex=args.force_reindex,
            batch_size=args.batch_size,
        )
        print(json.dumps(res, indent=2))
        return 0
    finally:
        store.close()


def cmd_query(args) -> int:
    store = VectorStoreSQLite(args.db)
    try:
        embedder = _build_embedder(args)
        rag = RAGSystem(
            store=store,
            embedder=embedder,
            llm_model=args.llm_model,
            api_key=args.openai_api_key,
            base_url=args.openai_base_url,
            max_context_chars=args.max_context_chars,
        )

        if args.retrieval_only:
            retrieved = rag.retrieve(args.q, top_k=args.top_k)
            out = {
                "query": args.q,
                "retrieved": [
                    {
                        "chunk_id": r.chunk_id,
                        "source": r.source,
                        "chunk_index": r.chunk_index,
                        "score": r.score,
                        "text": r.text,
                        "meta": r.meta,
                    }
                    for r in retrieved
                ],
                "prompt_messages": rag.build_prompt(args.q, retrieved),
            }
            print(json.dumps(out, indent=2, ensure_ascii=False))
            return 0

        out = rag.answer(args.q, top_k=args.top_k, temperature=args.temperature)
        print(json.dumps(out, indent=2, ensure_ascii=False))
        return 0
    finally:
        store.close()


def cmd_chat(args) -> int:
    store = VectorStoreSQLite(args.db)
    try:
        embedder = _build_embedder(args)
        rag = RAGSystem(
            store=store,
            embedder=embedder,
            llm_model=args.llm_model,
            api_key=args.openai_api_key,
            base_url=args.openai_base_url,
            max_context_chars=args.max_context_chars,
        )
        print("RAG chat. Type /exit to quit, /sources to list indexed sources.")
        while True:
            try:
                q = input("\nYou> ").strip()
            except (EOFError, KeyboardInterrupt):
                break
            if not q:
                continue
            if q.lower() in ("/exit", "exit", "quit", "/quit"):
                break
            if q.lower() in ("/sources", "sources"):
                print("\n".join(store.list_sources()))
                continue
            try:
                out = rag.answer(q, top_k=args.top_k, temperature=args.temperature) if not args.retrieval_only else {
                    "query": q,
                    "retrieved": [r.__dict__ for r in rag.retrieve(q, top_k=args.top_k)],
                }
                if args.retrieval_only:
                    for r in out["retrieved"]:
                        print(f"\n[{r['score']:.4f}] {r['source']} :: chunk {r['chunk_index']}\n{r['text'][:800]}")
                else:
                    print("\nAssistant>\n" + out["answer"])
            except Exception as e:
                print(f"Error: {e}")
        return 0
    finally:
        store.close()


def _parse_args():
    p = argparse.ArgumentParser(description="Simple Python RAG system (SQLite vector store).")
    p.add_argument("--db", default=os.environ.get("RAG_DB", "./rag_store.sqlite3"))
    p.add_argument("--embedder", choices=["openai", "st"], default=os.environ.get("RAG_EMBEDDER", "openai"))
    p.add_argument("--embedding-model", default=os.environ.get("RAG_EMBEDDING_MODEL", "text-embedding-3-large"))
    p.add_argument("--st-model", default=os.environ.get("RAG_ST_MODEL", "sentence-transformers/all-MiniLM-L6-v2"))
    p.add_argument("--llm-model", default=os.environ.get("RAG_LLM_MODEL", "gpt-4.1-mini"))
    p.add_argument("--openai-api-key", default=os.environ.get("OPENAI_API_KEY"))
    p.add_argument("--openai-base-url", default=os.environ.get("OPENAI_BASE_URL"))
    p.add_argument("--max-context-chars", type=int, default=int(os.environ.get("RAG_MAX_CONTEXT_CHARS", "60000")))

    sub = p.add_subparsers(dest="cmd", required=True)

    pi = sub.add_parser("ingest", help="Ingest documents into the vector store.")
    pi.add_argument("--docs", required=True, help="Directory containing company documents (txt/md).")
    pi.add_argument("--chunk-size", type=int, default=1200)
    pi.add_argument("--chunk-overlap", type=int, default=200)
    pi.add_argument("--batch-size", type=int, default=64)
    pi.add_argument("--force-reindex", action="store_true")
    pi.add_argument("--include-globs", nargs="*", default=["**/*.txt", "**/*.md"])
    pi.add_argument("--exclude-globs", nargs="*", default=[])
    pi.set_defaults(func=cmd_ingest)

    pq = sub.add_parser("query", help="Run a single query (retrieve + generate).")
    pq.add_argument("-q", required=True, help="User query.")
    pq.add_argument("--top-k", type=int, default=8)
    pq.add_argument("--temperature", type=float, default=0.2)
    pq.add_argument("--retrieval-only", action="store_true")
    pq.set_defaults(func=cmd_query)

    pc = sub.add_parser("chat", help="Interactive chat loop.")
    pc.add_argument("--top-k", type=int, default=8)
    pc.add_argument("--temperature", type=float, default=0.2)
    pc.add_argument("--retrieval-only", action="store_true")
    pc.set_defaults(func=cmd_chat)

    return p.parse_args()


def main():
    args = _parse_args()
    return args.func(args)


if __name__ == "__main__":
    raise SystemExit(main())